external_knowledge:
- "lit up the stage" refers to scoring goals;
- "shone in the spotlight" refers to the count of how many times a team is listed in the results, which indirectly indicates the total goals scored;
- "the grand theater of the first season" refers to the first season of the league.

sql:
SELECT season_id, AVG(goals_for) AS average_goals_scored
FROM league_results
GROUP BY season_id;

SELECT player_name, goals_scored
FROM team_players
ORDER BY goals_scored DESC;

